      assert rx > gcc + ghalf;
    }
    rx := rx + 1;
  }
  if rx <= gcc + ghalf {
    assert grid[ly][rx] == 'B';
    assert CellInSquare(ly, rx, gcr, gcc, ghalf);
    assert rx <= gcc + ghalf;
  }
  assert rx > gcc + ghalf;

  // Compute center
  var y := (ly + ry) / 2;
  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

  assert (ly + ry) == 2 * gcr + 1;
